class Solution:
    def maximumSumOfHeights(self, heights):
        n = len(heights)
        best = 0
        for p in range(n):
            run = float('inf')
            left_sum = 0
            for j in range(p, -1, -1):
                run = min(run, heights[j])
                left_sum += run
            run = float('inf')
            right_sum = 0
            for j in range(p, n):
                run = min(run, heights[j])
                right_sum += run
            total = left_sum + right_sum - heights[p]
            if total > best:
                best = total
        return best

