class Solution:
    def maximumSumOfHeights(self, heights):
        def one_side(arr):
            res = [0] * len(arr)
            stack = []  # (height, run_length)
            total = 0
            for i, h in enumerate(arr):
                cnt = 1
                while stack and stack[-1][0] > h:
                    ph, pc = stack.pop()
                    total -= ph * pc
                    cnt += pc
                stack.append((h, cnt))
                total += h * cnt
                res[i] = total
            return res

        left = one_side(heights)
        right = one_side(heights[::-1])[::-1]
        return max(l + r - h for l, r, h in zip(left, right, heights))

