var maximumSumOfHeights = function(heights) {
    const n = heights.length;
    function oneSide(arr) {
        const res = new Array(arr.length).fill(0);
        const stack = []; // [height, runLength]
        let total = 0;
        for (let i = 0; i < arr.length; i++) {
            const h = arr[i];
            let cnt = 1;
            while (stack.length && stack[stack.length - 1][0] > h) {
                const [ph, pc] = stack.pop();
                total -= ph * pc;
                cnt += pc;
            }
            stack.push([h, cnt]);
            total += h * cnt;
            res[i] = total;
        }
        return res;
    }
    const left = oneSide(heights);
    const rightRev = oneSide(heights.slice().reverse());
    const right = rightRev.slice().reverse();
    let best = 0;
    for (let i = 0; i < n; i++) {
        const total = left[i] + right[i] - heights[i];
        if (total > best) best = total;
    }
    return best;
};
